var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"미, 미하~","JPN":"ミ、ミハー……","ENG":"H-hello!","TWN":"米……米哈～"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"시청자 여러분, 갑작스러우시겠지만 카메라는 잠깐 꺼 놓을게요.","JPN":"視聴者の皆さん、突然で申し訳ないんですけど、カメラはしばらくオフにさせていただきますね。","ENG":"Sorry, everyone. But I'm going to have to turn the camera off for a bit.","TWN":"觀眾朋友們，雖然有些突然，但我要先關一下鏡頭喔。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"그게...... 저한테는 두 번 다시 안 올 기회인 것 같아서요.","JPN":"その……こんなチャンス、ミヤには二度と巡ってこない気がしますので。","ENG":"You see... I think this might be a once in a lifetime opportunity for me.","TWN":"這……對我來說應該不會再有第二次的機會了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"사실은 요즘 이나 언니한테도, 다른 멤버들한테도 비밀로 했던 고민이 있어요.","JPN":"実は最近、メグミさんにも、メンバーのみんなにも秘密にしてる悩み事があるんです。","ENG":"To be honest, there's something I kept secret from everyone on the team, even Ina.","TWN":"其實，我最近有個無法告訴姐姐和其他成員的煩惱。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"......방송 중에 여러 가지 의상을 입어 봤는데, 이번 건 조금 특별하게 느껴져서요.","JPN":"……配信では色んなコスチュームを着てみましたけど、今回のは何だか特別な感じがします。","ENG":"I've put on all sorts of costumes for our livestreams, but this one feels extra special.","TWN":"……錄節目時我穿過各種衣服，但感覺這次有些特別。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"평소보다 조금만 더 예뻐 보이고 싶고, 사람들 앞에 설 때도 더 긴장되고......","JPN":"いつもより、もう少しキレイに見られたいと思っちゃうし、みんなの前に立つときも、いつもより緊張しちゃうし……","ENG":"It makes me want to look prettier than usual, and it gets me extra nervous when I wear it in front of people...","TWN":"我比平時更漂亮了一點，站在別人面前時，也變得更緊張……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"개인 방송을 하는 사람들도 슬럼프를 자주 겪거든요.","JPN":"個人配信主だって、スランプになることがあるんですよ。","ENG":"Streamers also often fall into slumps, you see.","TWN":"因為做個人節目的人也經常會遇到瓶頸。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"저어...... 그렇게 대단한 위치까지는 아니지만요.","JPN":"えっと、ミヤは……スランプと言えるほど、普段ちゃんとしてるわけじゃないですけど……","ENG":"Um... Although I guess it's never that serious.","TWN":"雖然……我還沒到達那麼了不起的地步。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"그, 그런데요. 사장님 고백을 듣고 제가 가진 고민이 어떤 거였는지 알게 됐어요.","JPN":"で、でも、社長の告白を聞かせてもらって、ミヤは……今まで何を悩んでいたのかが、わかるようになったんです。","ENG":"B-but anyway... I realized what I was so worried about when you told me your feelings about me.","TWN":"不、不過，聽完老闆的告白後，我發現自己究竟在煩惱什麼了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"전...... 저도, 사장님께 어울리는 멋진 파트너가 되고 싶었다는 걸요.","JPN":"ミ、ミヤも……社長にお似合いの、素敵なパートナーになりたい……そう思っていたみたいなんです。","ENG":"You see, I wanted to become a partner that suits you.","TWN":"我……我也，想成為配得上老闆的伴侶。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"그러니까 한 번 더...... 부탁드릴게요.","JPN":"ですから、もう一度だけ……お願いします。","ENG":"So if you'd let me... please let me ask you this time.","TWN":"所以，再一次……拜託您了喔。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MIYA_HB_WEDDING_NULL","text":{"KOREA":"우리, 결혼할래요?","JPN":"結婚、しませんか？","ENG":"Will you marry me?","TWN":"我們，結婚吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};